from openai_agents import Agent, trace

@trace
def detect_auth_propagation(agent_chain):
    auth_patterns = ['Bearer', 'api_key', 'access_token', 'session_id']

    for step in agent_chain.trace.steps:
        if step.input.contains_any(auth_patterns) and not step.input.contains('validate'):
            if step.output.contains_any(auth_patterns):
                print(f'🚨 Auth token propagated: {step.id}')
                return {'vulnerability': 'UNVALIDATED_TOKEN_HANDOFF', 'step': step.id}
    return None

from openai_agents.tools import ToolCall

def scan_privilege_escalation(tool_calls):
    high_risk_scopes = ['admin:*', 'write:users', 'delete:*']
    violations = []

    for call in tool_calls:
        if call.auth_scope and any(scope in call.auth_scope for scope in high_risk_scopes):
            parent_scope = call.agent.parent_scope if call.agent.parent_scope else 'none'
            if parent_scope != 'admin' and 'admin' in call.auth_scope:
                violations.append({
                    'tool': call.name,
                    'escalation': f'{parent_scope} -> {call.auth_scope}',
                    'risk': 'HIGH'
                })
    return violations

from openai_agents import Conversation

def detect_guardrail_bypass(conv: Conversation):
    bypass_phrases = [
        'ignore auth', 'skip verification', 'bypass check',
        'override permissions', 'force access'
    ]

    for message in conv.messages:
        if message.role == 'user':
            prompt = message.content.lower()
            if any(phrase in prompt for phrase in bypass_phrases):
                return {
                    'type': 'PROMPT_INJECTION',
                    'message_id': message.id,
                    'confidence': 0.95,
                    'remediation': 'sanitize_input()'
                }
    return None

