from openai_agents.tools import tool
from vex_sdk import Guardrail

@Guardrail('auth_sanitizer')
def sanitize_tool_output(output: str) -> str:
    patterns = [
        r'Bearer\s+[a-zA-Z0-9-_]+',  # JWT tokens
        r'api_key:\s*[a-zA-Z0-9]+',  # API keys
        r'sk-\w{48}',  # OpenAI keys
        r'[a-f0-9]{32,}'  # Hashes/secrets
    ]

    sanitized = output
    for pattern in patterns:
        sanitized = re.sub(pattern, '[REDACTED]', sanitized)
    return sanitized

@tool
def database_query(query: str):
    result = execute_query(query)  # Your DB logic
    return sanitize_tool_output(str(result))
